    use clap::Parser;

    // Re-declare the CLI to test parsing in isolation.
    // The structs must match exactly what is in src/main.rs.

    #[derive(clap::Parser, Debug)]
    #[command(name = "zeroclaw")]
    struct Cli {
        #[command(subcommand)]
        command: Commands,
    }

    #[derive(clap::Subcommand, Debug)]
    enum Commands {
        Onboard {
            #[arg(long)]
            force: bool,
            #[arg(long)]
            quick: bool,
            #[arg(long)]
            channels_only: bool,
            #[arg(long)]
            api_key: Option<String>,
            #[arg(long)]
            provider: Option<String>,
            #[arg(long)]
            model: Option<String>,
            #[arg(long)]
            memory: Option<String>,
            #[arg(long)]
            reinit: bool,
            #[arg(long)]
            tui: bool,
        },
        Props {
            #[command(subcommand)]
            props_command: PropsCommands,
        },
    }

    #[derive(clap::Subcommand, Debug, PartialEq)]
    enum PropsCommands {
        /// List all config properties
        List {
            /// Filter by path prefix
            #[arg(long)]
            filter: Option<String>,
            /// Show secret fields (set/unset status only)
            #[arg(long)]
            secrets: bool,
        },
        /// Get the current value of a property
        Get {
            /// Dot-separated property path (e.g. "gateway.port")
            path: String,
        },
