        Set {
            /// Dot-separated property path
            path: String,
            /// New value (secrets read interactively if omitted)
            value: Option<String>,
        },
        /// Initialize unconfigured sections with defaults
        Init {
            /// Optional section prefix to limit initialization
            section: Option<String>,
