        let cli = Cli::try_parse_from(["zeroclaw", "props", "init", "channels.telegram"])
            .expect("props init with section should parse");
        match cli.command {
            Commands::Props { props_command } => {
                assert_eq!(props_command, PropsCommands::Init {
                    section: Some("channels.telegram".into()),
                });
            }
            _ => panic!("expected Props command"),
        }
    }

    #[test]
    fn props_complete_parses() {
        let cli = Cli::try_parse_from(["zeroclaw", "props", "complete", "gate"])
            .expect("props complete should parse");
        match cli.command {
            Commands::Props { props_command } => {
                assert_eq!(props_command, PropsCommands::Complete {
                    partial: Some("gate".into()),
                });
            }
            _ => panic!("expected Props command"),
        }
    }

    #[test]
    fn props_complete_no_partial_parses() {
        let cli = Cli::try_parse_from(["zeroclaw", "props", "complete"])
            .expect("props complete without partial should parse");
        match cli.command {
            Commands::Props { props_command } => {
                assert_eq!(props_command, PropsCommands::Complete { partial: None });
            }
            _ => panic!("expected Props command"),
        }
    }
}

