//! Config property management via `zeroclaw props` CLI.
//!
//! Provides `props list`, `props get`, `props set`, `props init`, and
//! `props complete` subcommands for inspecting and modifying individual
//! properties in `config.toml` without re-running the full onboard wizard.
//!
//! Secrets are handled specially:
//! - `list` shows set/unset status rather than raw values
//! - `set` reads secret values interactively via masked input when no value is given
//! - `get` shows set/unset status rather than raw values
//!
//! Introduced in PR #5165.

use crate::config::Config;
use anyhow::{Context, Result, bail};
use std::io::Write;

/// Subcommands of `zeroclaw props`.
#[derive(clap::Subcommand, Debug, Clone, PartialEq, Eq)]
pub enum PropsCommand {
    /// List all config properties (or filter by prefix)
    List {
        /// Filter properties by path prefix
        #[arg(long)]
        filter: Option<String>,
        /// Show secret fields (set/unset status only)
        #[arg(long)]
        secrets: bool,
    },
    /// Get the current value of a property
    Get {
        /// Dot-separated property path (e.g. "gateway.port")
        path: String,
    },
    /// Set a property value
    Set {
        /// Dot-separated property path (e.g. "gateway.port")
        path: String,
        /// New value (secrets read interactively via masked input if omitted)
        value: Option<String>,
    },
    /// Initialize unconfigured sections with defaults
    Init {
        /// Optional section prefix to limit initialization (e.g. "channels.telegram")
        section: Option<String>,
    },
    /// Dynamic shell tab-completion for property paths
    Complete {
        /// Partial dot-separated path to complete (e.g. "gate" → "gateway.")
        partial: Option<String>,
    },
}

/// List all known config properties with their current values.
///
/// Properties are written as `PATH=TYPE=VALUE` lines to stdout.
/// If `filter` is provided, only properties whose path starts with
/// the filter prefix are shown.
/// If `secrets` is true, secret properties are included with their
/// set/unset status instead of values.
pub fn list_props(config: &Config, filter: Option<&str>, show_secrets: bool) -> Result<()> {
    let props = gather_properties(config);

    let mut stdout = std::io::stdout().lock();
    for prop in &props {
        // Apply filter if specified
        if let Some(f) = filter {
            if !prop.path.starts_with(f) {
                continue;
            }
        }

        // Skip secrets unless requested
        if prop.is_secret && !show_secrets {
            continue;
        }

        if prop.is_secret {
            let status = if prop.value == "***" || prop.value.is_empty() {
                "unset"
            } else {
                "set"
            };
            writeln!(stdout, "{}={}={} [secret]", prop.path, prop.ty, status)?;
        } else {
            writeln!(stdout, "{}={}={}", prop.path, prop.ty, prop.value)?;
        }
    }

    Ok(())
}

/// Get the current value of a single config property by its dot-separated path.
///
/// For secrets, shows set/unset status rather than the raw value.
pub fn get_prop(config: &Config, path: &str) -> Result<()> {
    let props = gather_properties(config);

    let prop = props
        .iter()
        .find(|p| p.path == path)
        .with_context(|| format!("property '{}' not found", path))?;

    let stdout = std::io::stdout().lock();
    let mut stdout = stdout;

    if prop.is_secret {
        let status = if prop.value == "***" || prop.value.is_empty() {
            "unset"
        } else {
            "set"
        };
        writeln!(stdout, "{}={} status={}", prop.path, prop.ty, status)?;
    } else {
        writeln!(stdout, "{}={}={}", prop.path, prop.ty, prop.value)?;
    }

    Ok(())
}

/// Set a config property to a new value.
///
/// If `value` is `None` and the property is a secret, reads interactively
/// via masked input (stdin).
pub fn set_prop(config: &mut Config, path: &str, value: Option<&str>) -> Result<()> {
    let props = gather_properties(config);

    let prop = props
        .iter()
        .find(|p| p.path == path)
        .with_context(|| format!("property '{}' not found", path))?;

    let new_value = match value {
        Some(v) => v.to_string(),
        None => {
            if prop.is_secret {
                // Read secret value interactively with masked input
                let entered = rpassword::prompt_password(format!("Enter value for {}: ", path))
                    .context("Failed to read secret value")?;
                if entered.is_empty() {
                    bail!("secret value cannot be empty");
                }
                entered
            } else {
                bail!(
                    "property '{}' requires a value. Usage: zeroclaw props set {} <value>",
                    path,
                    path
                );
            }
        }
    };

    // Persist the config
    apply_property_update(config, path, &new_value)?;

    println!("Property '{}' updated.", path);
    Ok(())
}

/// Initialize unconfigured sections with default values.
///
/// If `section` is provided, only properties under that prefix are affected.
pub fn init_props(config: &mut Config, section: Option<&str>) -> Result<()> {
    let sections: Vec<&str> = vec![
        "gateway",
        "heartbeat",
        "security",
        "memory",
        "observability",
        "autonomy",
        "secrets",
        "cron",
        "skills",
        "browser",
        "sandbox",
        "tunnel",
        "peripherals",
        "tools",
    ];

    let mut initialized_count = 0;

    for sec in &sections {
        if let Some(filter) = section {
            if *sec != filter && !sec.starts_with(filter) && !filter.starts_with(sec) {
                continue;
            }
        }

        // Initialize the section by touching its default settings
        // This writes default values for any missing keys under the section
        match init_section(config, sec) {
            Ok(count) => {
                initialized_count += count;
            }
            Err(e) => {
                eprintln!("Warning: could not init section '{}': {}", sec, e);
            }
        }
    }

    println!("Initialized {} properties across {} sections.", initialized_count, sections.len());
    Ok(())
}

/// Print completions for property paths given a partial input.
///
/// Used for shell tab-completion. Outputs one completion per line.
pub fn complete_props(config: &Config, partial: Option<&str>) -> Result<()> {
    let props = gather_properties(config);
    let prefix = partial.unwrap_or("");

    let mut completions: Vec<String> = props
        .iter()
        .filter(|p| p.path.starts_with(prefix))
        .map(|p| p.path.clone())
        .collect();

    completions.sort();
    completions.dedup();

    // Also suggest next-level prefixes for partial matches
    let mut prefixes: Vec<String> = props
        .iter()
        .filter_map(|p| {
            // Find the first '.' after the prefix
            let rest = p.path.strip_prefix(prefix)?;
            let next_dot = rest.find('.')?;
            let segment = &rest[..next_dot];
            Some(format!("{}{}.", prefix, segment))
        })
        .collect();

    prefixes.sort();
    prefixes.dedup();

    let mut stdout = std::io::stdout().lock();
    for c in &completions {
        writeln!(stdout, "{}", c)?;
    }
    for p in &prefixes {
        writeln!(stdout, "{}", p)?;
    }

    Ok(())
}

