/// Initialize a section with default values.
fn init_section(config: &mut Config, section: &str) -> Result<usize> {
    let mut count = 0;

    match section {
        "gateway" => {
            // Gateway defaults are set during onboard; nothing to init here.
        }
        "heartbeat" => {
            if !config.heartbeat.enabled {
                config.heartbeat.enabled = true;
                count += 1;
            }
        }
        "memory" => {
            if !config.memory.auto_save {
                config.memory.auto_save = true;
                count += 1;
            }
        }
        "cron" => {
            if !config.cron.enabled {
                config.cron.enabled = true;
                count += 1;
            }
        }
        "browser" => {
            if !config.browser.enabled {
                config.browser.enabled = true;
                count += 1;
            }
        }
        "sandbox" => {
            // Already has a default
        }
        "tunnel" => {
            if !config.tunnel.enabled {
                config.tunnel.enabled = true;
                count += 1;
            }
        }
        "peripherals" => {
            if !config.peripherals.enabled {
                config.peripherals.enabled = true;
                count += 1;
            }
        }
        _ => {
            // Unknown section; no-op
        }
    }

    Ok(count)
}

/// Apply a property update to config and persist it.
fn apply_property_update(config: &mut Config, path: &str, value: &str) -> Result<()> {
    match path {
        "api_key" => {
            config.api_key = Some(value.to_string());
        }
        "default_provider" => {
            config.default_provider = Some(value.to_string());
        }
        "default_model" => {
            config.default_model = Some(value.to_string());
        }
        "gateway.port" => {
            config.gateway.port = value.parse().context("port must be a u16")?;
        }
        "gateway.host" => {
            config.gateway.host = value.to_string();
        }
        "gateway.require_pairing" => {
            config.gateway.require_pairing =
                value.parse().context("require_pairing must be true/false")?;
        }
        "heartbeat.enabled" => {
            config.heartbeat.enabled = value.parse().context("enabled must be true/false")?;
        }
        "heartbeat.interval_minutes" => {
            config.heartbeat.interval_minutes =
                value.parse().context("interval_minutes must be a number")?;
        }
        "security.estop.enabled" => {
            config.security.estop.enabled = value.parse().context("enabled must be true/false")?;
        }
        "autonomy.level" => {
            config.autonomy.level = serde_json::from_str(&format!("\"{}\"", value))
                .context("invalid autonomy level")?;
        }
        "autonomy.workspace_only" => {
            config.autonomy.workspace_only =
                value.parse().context("workspace_only must be true/false")?;
        }
        "autonomy.max_actions_per_hour" => {
            config.autonomy.max_actions_per_hour =
                value.parse().context("max_actions_per_hour must be a number")?;
        }
        "memory.backend" => {
            config.memory.backend = value.to_string();
        }
        "memory.auto_save" => {
            config.memory.auto_save = value.parse().context("auto_save must be true/false")?;
        }
        "cron.enabled" => {
            config.cron.enabled = value.parse().context("enabled must be true/false")?;
        }
        "cost.enabled" => {
            config.cost.enabled = value.parse().context("enabled must be true/false")?;
        }
        "cost.daily_limit_usd" => {
            config.cost.daily_limit_usd = value.parse().context("daily_limit_usd must be a number")?;
        }
        "cost.monthly_limit_usd" => {
            config.cost.monthly_limit_usd =
                value.parse().context("monthly_limit_usd must be a number")?;
        }
        "skills.enabled" => {
            config.skills.enabled = value.parse().context("enabled must be true/false")?;
        }
        "browser.enabled" => {
            config.browser.enabled = value.parse().context("enabled must be true/false")?;
        }
        "tunnel.enabled" => {
            config.tunnel.enabled = value.parse().context("enabled must be true/false")?;
        }
        "peripherals.enabled" => {
            config.peripherals.enabled = value.parse().context("enabled must be true/false")?;
        }
        other => bail!("property '{}' is not settable via props CLI", other),
    }

    Ok(())
}

